// Human Body & Health quiz data — 500 questions for children aged 7-12
quizData["Human Body"] = [
    // ===== THE SKELETON (1-50) =====
    { question: "How many bones does an adult human have?", options: ["106", "206", "306"], answer: 1, explanation: "An adult human has 206 bones — but babies are born with about 270 that fuse together as they grow!" },
    { question: "How many bones does a baby have?", options: ["About 100", "About 206", "About 270"], answer: 2, explanation: "Babies are born with about 270 bones — many are soft cartilage that fuses together as they grow!" },
    { question: "What is the longest bone in the body?", options: ["The spine", "The femur (thigh bone)", "The humerus (upper arm)"], answer: 1, explanation: "The femur (thigh bone) is the longest bone — it's about one quarter of your total height!" },
    { question: "What is the smallest bone in the body?", options: ["A toe bone", "The stapes (in the ear)", "A finger bone"], answer: 1, explanation: "The stapes in your middle ear is only about 3 mm long — the smallest bone in your body!" },
    { question: "What are bones made of?", options: ["Just calcium", "Living tissue with calcium, collagen, and blood vessels", "Solid rock-like material"], answer: 1, explanation: "Bones are living tissue made of calcium, collagen (a protein), blood vessels, and nerves — they can heal when broken!" },
    { question: "What is the hard outer layer of bone called?", options: ["Cartilage", "Compact bone", "Spongy bone"], answer: 1, explanation: "The hard outer layer is compact bone — it's very dense and strong, giving bones their strength!" },
    { question: "What is bone marrow?", options: ["A type of food", "Soft tissue inside bones that makes blood cells", "The outside of a bone"], answer: 1, explanation: "Bone marrow is soft tissue inside bones — it makes millions of new blood cells every day!" },
    { question: "What is a joint?", options: ["A type of bone", "Where two or more bones meet", "A muscle"], answer: 1, explanation: "A joint is where two or more bones meet — joints allow your body to move and bend!" },
    { question: "What type of joint is your knee?", options: ["Ball and socket", "Hinge joint", "Pivot joint"], answer: 1, explanation: "Your knee is a hinge joint — it moves back and forth like a door hinge!" },
    { question: "What type of joint is your shoulder?", options: ["Hinge joint", "Ball and socket joint", "Fixed joint"], answer: 1, explanation: "Your shoulder is a ball and socket joint — it allows movement in many directions!" },
    { question: "What type of joint is your hip?", options: ["Hinge joint", "Pivot joint", "Ball and socket joint"], answer: 2, explanation: "Your hip is a ball and socket joint — the round head of the femur fits into a cup-shaped socket!" },
    { question: "What protects the ends of bones at joints?", options: ["Skin", "Cartilage", "Muscle"], answer: 1, explanation: "Cartilage is a smooth, rubbery tissue that covers the ends of bones at joints — it reduces friction!" },
    { question: "What are the bones in your spine called?", options: ["Ribs", "Vertebrae", "Phalanges"], answer: 1, explanation: "The bones in your spine are called vertebrae — you have 33 of them stacked on top of each other!" },
    { question: "How many vertebrae are in your spine?", options: ["12", "26", "33"], answer: 2, explanation: "You have 33 vertebrae — 7 in your neck, 12 in your upper back, 5 in your lower back, and 9 fused ones!" },
    { question: "What protects your brain?", options: ["Your hair", "Your skull", "Your skin"], answer: 1, explanation: "Your skull is a strong bony shell that protects your brain — it's made up of 22 bones!" },
    { question: "How many ribs do most people have?", options: ["10", "12 pairs (24 total)", "14 pairs (28 total)"], answer: 1, explanation: "Most people have 12 pairs of ribs (24 total) — they protect your heart and lungs!" },
    { question: "What is your kneecap called?", options: ["Patella", "Tibia", "Fibula"], answer: 0, explanation: "Your kneecap is called the patella — it's a small, flat bone that protects the front of your knee joint!" },
    { question: "What connects bones to other bones?", options: ["Tendons", "Ligaments", "Muscles"], answer: 1, explanation: "Ligaments are tough bands of tissue that connect bones to other bones at joints!" },
    { question: "What connects muscles to bones?", options: ["Ligaments", "Tendons", "Nerves"], answer: 1, explanation: "Tendons are strong cords of tissue that connect muscles to bones — like the Achilles tendon in your heel!" },
    { question: "What is the collarbone called?", options: ["Scapula", "Clavicle", "Sternum"], answer: 1, explanation: "The collarbone is called the clavicle — it connects your shoulder blade to your breastbone!" },
    { question: "What is your breastbone called?", options: ["Sternum", "Scapula", "Clavicle"], answer: 0, explanation: "Your breastbone is called the sternum — your ribs connect to it at the front of your chest!" },
    { question: "What are the bones in your fingers called?", options: ["Carpals", "Phalanges", "Metacarpals"], answer: 1, explanation: "The bones in your fingers (and toes) are called phalanges — you have 14 in each hand!" },
    { question: "How many bones are in your hand and wrist?", options: ["8", "15", "27"], answer: 2, explanation: "Your hand and wrist contain 27 bones — 8 carpals, 5 metacarpals, and 14 phalanges!" },
    { question: "What is the funny bone actually?", options: ["A bone in your elbow", "The ulnar nerve hitting the humerus", "A small bone in your wrist"], answer: 1, explanation: "The 'funny bone' isn't a bone — it's your ulnar nerve hitting the humerus bone, causing a tingling sensation!" },
    { question: "What are the two bones in your lower leg?", options: ["Femur and patella", "Tibia and fibula", "Humerus and radius"], answer: 1, explanation: "The tibia (shin bone) and fibula are the two bones in your lower leg — the tibia is the larger one!" },
    { question: "What is osteoporosis?", options: ["A type of fracture", "A condition where bones become weak and brittle", "A muscle disease"], answer: 1, explanation: "Osteoporosis makes bones weak and brittle — eating calcium-rich foods and exercising helps keep bones strong!" },
    { question: "What food is good for strong bones?", options: ["Sweets", "Milk, cheese, and yoghurt", "Crisps"], answer: 1, explanation: "Dairy products, leafy greens, and fish are great for bones because they're rich in calcium and vitamin D!" },
    { question: "How long does a broken bone usually take to heal?", options: ["About 1 day", "About 6-8 weeks", "About 1 year"], answer: 1, explanation: "Most broken bones take about 6-8 weeks to heal — your body creates new bone tissue to repair the break!" },
    { question: "What is the strongest bone in the body?", options: ["The skull", "The femur", "The spine"], answer: 1, explanation: "The femur is the strongest bone — it can support 30 times your body weight!" },
    { question: "Where is the only bone not connected to another bone?", options: ["In your ear", "In your throat (hyoid bone)", "In your toe"], answer: 1, explanation: "The hyoid bone in your throat is the only bone not connected to any other bone — it helps you speak and swallow!" },

    // ===== MUSCLES (51-100) =====
    { question: "How many muscles are in the human body?", options: ["About 100", "About 400", "About 600"], answer: 2, explanation: "The human body has about 600 muscles — they make up about 40% of your body weight!" },
    { question: "What is the largest muscle in the body?", options: ["The bicep", "The gluteus maximus (bottom)", "The heart"], answer: 1, explanation: "The gluteus maximus — your bottom muscle — is the largest muscle in the body!" },
    { question: "What is the smallest muscle in the body?", options: ["In your finger", "The stapedius (in your ear)", "In your toe"], answer: 1, explanation: "The stapedius in your middle ear is the smallest muscle — it's only about 1 mm long!" },
    { question: "What are the three types of muscle?", options: ["Big, medium, small", "Skeletal, smooth, cardiac", "Arm, leg, core"], answer: 1, explanation: "The three types are skeletal (moves bones), smooth (in organs), and cardiac (heart muscle)!" },
    { question: "Which type of muscle can you control?", options: ["Smooth muscle", "Cardiac muscle", "Skeletal muscle"], answer: 2, explanation: "Skeletal muscles are voluntary — you can control them to walk, wave, or pick things up!" },
    { question: "Which type of muscle works automatically?", options: ["Skeletal muscle", "Smooth and cardiac muscle", "Only arm muscles"], answer: 1, explanation: "Smooth muscle (in organs) and cardiac muscle (heart) work automatically — you don't have to think about them!" },
    { question: "What makes muscles move?", options: ["Air", "Signals from the brain through nerves", "Blood pressure"], answer: 1, explanation: "Your brain sends electrical signals through nerves to tell muscles to contract (shorten) and move!" },
    { question: "Do muscles push or pull?", options: ["They only push", "They only pull", "They push and pull"], answer: 1, explanation: "Muscles can only pull (contract) — they work in pairs so one pulls one way while the other pulls back!" },
    { question: "What muscle pair is in your upper arm?", options: ["Gluteus and quadriceps", "Biceps and triceps", "Hamstrings and calves"], answer: 1, explanation: "Your biceps (front) and triceps (back) work as a pair — when one contracts, the other relaxes!" },
    { question: "What happens when you flex your arm?", options: ["The triceps contracts", "The biceps contracts", "Both muscles relax"], answer: 1, explanation: "When you flex your arm, your biceps contracts (shortens) and your triceps relaxes (lengthens)!" },
    { question: "What muscle helps you breathe?", options: ["The bicep", "The diaphragm", "The gluteus"], answer: 1, explanation: "The diaphragm is a dome-shaped muscle below your lungs — it contracts to pull air in and relaxes to push air out!" },
    { question: "What is a muscle cramp?", options: ["A broken muscle", "A sudden, involuntary muscle contraction", "A muscle growing"], answer: 1, explanation: "A cramp is when a muscle suddenly contracts and won't relax — it can be caused by dehydration or overuse!" },
    { question: "How many muscles does it take to smile?", options: ["About 2", "About 12", "About 43"], answer: 1, explanation: "It takes about 12 muscles to smile — fewer than the approximately 11 muscles needed to frown!" },
    { question: "What gives muscles their red colour?", options: ["Blood", "A protein called myoglobin", "Iron"], answer: 1, explanation: "Myoglobin is a protein in muscle tissue that stores oxygen and gives muscles their red colour!" },
    { question: "What is the strongest muscle by weight?", options: ["The tongue", "The masseter (jaw muscle)", "The bicep"], answer: 1, explanation: "The masseter (jaw muscle) is the strongest muscle based on its weight — it can produce about 90 kg of force!" },
    { question: "Can muscles grow?", options: ["No, you're born with all muscle", "Yes, exercise makes muscle fibres get bigger", "Only before age 10"], answer: 1, explanation: "Exercise causes muscle fibres to get bigger (hypertrophy) — though you don't grow new muscle cells, existing ones get larger!" },
    { question: "What is a tendon?", options: ["A type of muscle", "A tough cord connecting muscle to bone", "A type of bone"], answer: 1, explanation: "A tendon is a tough, flexible cord that connects a muscle to a bone — the Achilles tendon is the largest!" },
    { question: "Where is the Achilles tendon?", options: ["In your wrist", "At the back of your ankle", "In your elbow"], answer: 1, explanation: "The Achilles tendon connects your calf muscle to your heel bone — it's the strongest and largest tendon!" },
    { question: "Why do muscles get sore after exercise?", options: ["They're broken", "Tiny tears in muscle fibres cause inflammation", "They run out of blood"], answer: 1, explanation: "Exercise causes tiny tears in muscle fibres — your body repairs them and makes the muscle stronger!" },
    { question: "What is the muscle on the front of your thigh called?", options: ["Hamstring", "Quadriceps", "Calf"], answer: 1, explanation: "The quadriceps (or quads) are the four muscles on the front of your thigh — they help you kick and run!" },

    // ===== THE HEART & BLOOD (101-170) =====
    { question: "How big is your heart roughly?", options: ["The size of a grape", "About the size of your fist", "The size of a football"], answer: 1, explanation: "Your heart is about the size of your fist — and it never stops beating your entire life!" },
    { question: "How many times does your heart beat per day?", options: ["About 1,000", "About 10,000", "About 100,000"], answer: 2, explanation: "Your heart beats about 100,000 times every day — that's about 70-100 beats per minute!" },
    { question: "How much blood does your heart pump per day?", options: ["About 10 litres", "About 100 litres", "About 7,500 litres"], answer: 2, explanation: "Your heart pumps about 7,500 litres of blood every day — enough to fill a small swimming pool in a week!" },
    { question: "How many chambers does the heart have?", options: ["2", "3", "4"], answer: 2, explanation: "The heart has 4 chambers — two upper chambers (atria) and two lower chambers (ventricles)!" },
    { question: "What are the upper chambers of the heart called?", options: ["Ventricles", "Atria", "Valves"], answer: 1, explanation: "The upper chambers are called atria (singular: atrium) — they receive blood coming into the heart!" },
    { question: "What are the lower chambers of the heart called?", options: ["Atria", "Ventricles", "Arteries"], answer: 1, explanation: "The lower chambers are called ventricles — they pump blood out of the heart to the body and lungs!" },
    { question: "What type of blood vessel carries blood AWAY from the heart?", options: ["Veins", "Arteries", "Capillaries"], answer: 1, explanation: "Arteries carry blood away from the heart — they have thick, muscular walls to handle the pressure!" },
    { question: "What type of blood vessel carries blood TOWARD the heart?", options: ["Arteries", "Veins", "Capillaries"], answer: 1, explanation: "Veins carry blood back to the heart — they have valves to stop blood flowing backwards!" },
    { question: "What are capillaries?", options: ["Large blood vessels", "Tiny blood vessels where gas exchange happens", "Heart valves"], answer: 1, explanation: "Capillaries are tiny blood vessels so thin that blood cells pass through in single file — oxygen and nutrients pass through their walls!" },
    { question: "What gives blood its red colour?", options: ["Red blood cells containing haemoglobin", "Plasma", "White blood cells"], answer: 0, explanation: "Red blood cells contain haemoglobin, an iron-rich protein that carries oxygen — the iron gives blood its red colour!" },
    { question: "What do red blood cells do?", options: ["Fight infection", "Carry oxygen around the body", "Help blood to clot"], answer: 1, explanation: "Red blood cells carry oxygen from your lungs to every cell in your body, and carry carbon dioxide back!" },
    { question: "What do white blood cells do?", options: ["Carry oxygen", "Fight infections and diseases", "Help blood clot"], answer: 1, explanation: "White blood cells are part of your immune system — they fight bacteria, viruses, and other germs!" },
    { question: "What do platelets do?", options: ["Carry oxygen", "Fight germs", "Help blood to clot and stop bleeding"], answer: 2, explanation: "Platelets are tiny cell fragments that clump together to form blood clots — they stop you bleeding when you get a cut!" },
    { question: "What is plasma?", options: ["A type of blood cell", "The liquid part of blood", "A blood vessel"], answer: 1, explanation: "Plasma is the yellowish liquid that makes up about 55% of blood — it carries blood cells, nutrients, and hormones!" },
    { question: "How much blood does the average adult have?", options: ["About 1 litre", "About 5 litres", "About 15 litres"], answer: 1, explanation: "The average adult has about 5 litres of blood — that's about 7% of your body weight!" },
    { question: "What are the main blood types?", options: ["1, 2, 3, 4", "A, B, AB, O", "Red, white, blue"], answer: 1, explanation: "The main blood types are A, B, AB, and O — each can be positive or negative, making 8 types!" },
    { question: "What is the most common blood type?", options: ["A positive", "O positive", "AB negative"], answer: 1, explanation: "O positive is the most common blood type worldwide — about 38% of people have it!" },
    { question: "What is the rarest blood type?", options: ["O negative", "A positive", "AB negative"], answer: 2, explanation: "AB negative is the rarest blood type — only about 1% of people have it!" },
    { question: "How long do red blood cells live?", options: ["About 1 day", "About 120 days", "About 5 years"], answer: 1, explanation: "Red blood cells live for about 120 days — your body constantly makes new ones to replace old ones!" },
    { question: "Where are blood cells made?", options: ["In the heart", "In bone marrow", "In the lungs"], answer: 1, explanation: "Blood cells are made in bone marrow — the spongy tissue inside your bones produces millions every second!" },
    { question: "What is blood pressure?", options: ["How heavy your blood is", "The force of blood pushing against artery walls", "How fast blood flows"], answer: 1, explanation: "Blood pressure is the force of blood pushing against the walls of your arteries as your heart pumps!" },
    { question: "What is the pulse?", options: ["A blood vessel", "The rhythmic beating felt where arteries are close to skin", "A type of blood cell"], answer: 1, explanation: "Your pulse is the rhythmic throbbing of arteries as blood is pumped through them — you can feel it in your wrist or neck!" },
    { question: "If you lined up all your blood vessels, how long would they stretch?", options: ["About 1,000 km", "About 10,000 km", "About 100,000 km"], answer: 2, explanation: "If you laid out all your blood vessels end to end, they'd stretch about 100,000 km — enough to wrap around Earth 2.5 times!" },
    { question: "What side of the heart pumps blood to the lungs?", options: ["The left side", "The right side", "Both sides equally"], answer: 1, explanation: "The right side of the heart pumps blood to the lungs to pick up oxygen — the left side sends it to the rest of the body!" },
    { question: "What makes the 'lub-dub' sound of your heartbeat?", options: ["Blood flowing", "Heart valves opening and closing", "Muscles contracting"], answer: 1, explanation: "The 'lub-dub' sound is made by your heart valves closing — 'lub' is the larger valves, 'dub' is the smaller ones!" },

    // ===== THE BRAIN & NERVOUS SYSTEM (171-240) =====
    { question: "How much does the average adult brain weigh?", options: ["About 0.5 kg", "About 1.4 kg", "About 5 kg"], answer: 1, explanation: "The average adult brain weighs about 1.4 kg — only about 2% of body weight but uses 20% of your energy!" },
    { question: "What percentage of your body's energy does the brain use?", options: ["About 5%", "About 20%", "About 50%"], answer: 1, explanation: "Your brain uses about 20% of your body's total energy — it's the most energy-hungry organ!" },
    { question: "What are the two halves of the brain called?", options: ["Tops and bottoms", "Hemispheres", "Lobes"], answer: 1, explanation: "The brain has two hemispheres — left and right — connected by a bundle of nerve fibres called the corpus callosum!" },
    { question: "What is the wrinkly outer layer of the brain called?", options: ["The cerebellum", "The cerebral cortex", "The brain stem"], answer: 1, explanation: "The cerebral cortex is the wrinkly outer layer — the wrinkles give it more surface area for thinking!" },
    { question: "What part of the brain controls balance?", options: ["The cerebrum", "The cerebellum", "The brain stem"], answer: 1, explanation: "The cerebellum at the back of your brain controls balance, coordination, and smooth movements!" },
    { question: "What part of the brain controls breathing and heart rate?", options: ["The cerebrum", "The cerebellum", "The brain stem"], answer: 2, explanation: "The brain stem controls automatic functions like breathing, heart rate, and digestion — things you don't have to think about!" },
    { question: "How many neurons are in the brain?", options: ["About 1 million", "About 86 billion", "About 1 trillion"], answer: 1, explanation: "Your brain contains about 86 billion neurons — tiny nerve cells that send and receive electrical signals!" },
    { question: "What is a neuron?", options: ["A type of muscle", "A nerve cell that carries electrical signals", "A blood cell"], answer: 1, explanation: "A neuron is a nerve cell — it carries electrical signals throughout your brain and body!" },
    { question: "How fast can nerve signals travel?", options: ["About 1 km/h", "About 30 km/h", "Up to 430 km/h"], answer: 2, explanation: "Nerve signals can travel up to 430 km/h — that's why you can pull your hand away from something hot so quickly!" },
    { question: "What is the spinal cord?", options: ["A bone in your back", "A thick bundle of nerves running through your spine", "A muscle"], answer: 1, explanation: "The spinal cord is a thick bundle of nerves running through your spine — it carries signals between your brain and body!" },
    { question: "What protects the spinal cord?", options: ["Muscles", "The vertebrae of the spine", "Skin"], answer: 1, explanation: "The vertebrae (bones of the spine) form a protective tunnel around the delicate spinal cord!" },
    { question: "What is a reflex?", options: ["A type of exercise", "An automatic response that doesn't need the brain", "A thought process"], answer: 1, explanation: "A reflex is an automatic response — like pulling your hand from a hot stove — the signal goes to the spinal cord and back without reaching the brain first!" },
    { question: "What does the left side of the brain mainly control?", options: ["The left side of the body", "The right side of the body", "Both sides equally"], answer: 1, explanation: "The left brain controls the right side of your body and the right brain controls the left — they're cross-wired!" },
    { question: "What part of the brain is responsible for memory?", options: ["The cerebellum", "The hippocampus", "The brain stem"], answer: 1, explanation: "The hippocampus is key for forming and storing memories — it's shaped like a seahorse!" },
    { question: "What are the five main senses?", options: ["Thinking, feeling, moving, hearing, seeing", "Sight, hearing, smell, taste, touch", "Walking, talking, eating, sleeping, breathing"], answer: 1, explanation: "The five main senses are sight, hearing, smell, taste, and touch — all processed by your brain!" },
    { question: "Which sense is the strongest trigger for memory?", options: ["Sight", "Hearing", "Smell"], answer: 2, explanation: "Smell is the strongest trigger for memories — a familiar scent can instantly bring back vivid memories!" },
    { question: "How much of your brain is water?", options: ["About 30%", "About 55%", "About 75%"], answer: 2, explanation: "Your brain is about 75% water — that's why staying hydrated is so important for thinking clearly!" },
    { question: "Does the brain feel pain?", options: ["Yes, very sensitive", "No, the brain has no pain receptors", "Only during headaches"], answer: 1, explanation: "The brain itself has no pain receptors — headaches are caused by pain signals from surrounding tissues and blood vessels!" },
    { question: "What happens to your brain when you sleep?", options: ["It turns off", "It stays active — sorting memories and repairing", "It works the same as when awake"], answer: 1, explanation: "Your brain is very active during sleep — it sorts memories, removes waste, and repairs itself!" },
    { question: "What is the peripheral nervous system?", options: ["The brain", "All the nerves outside the brain and spinal cord", "The spine"], answer: 1, explanation: "The peripheral nervous system includes all the nerves branching out from the brain and spinal cord to the rest of your body!" },

    // ===== LUNGS & BREATHING (241-290) =====
    { question: "How many lungs do you have?", options: ["One", "Two", "Three"], answer: 1, explanation: "You have two lungs — the right lung has three lobes and the left lung has two (to make room for the heart)!" },
    { question: "Which lung is slightly smaller?", options: ["The right lung", "The left lung", "They're the same size"], answer: 1, explanation: "The left lung is slightly smaller than the right — it has a notch to make room for your heart!" },
    { question: "How many times do you breathe per minute?", options: ["About 5 times", "About 15-20 times", "About 50 times"], answer: 1, explanation: "You breathe about 15-20 times per minute at rest — that's about 20,000 breaths every day!" },
    { question: "What gas do you breathe in that your body needs?", options: ["Carbon dioxide", "Oxygen", "Nitrogen"], answer: 1, explanation: "You breathe in oxygen — your cells need it to release energy from food!" },
    { question: "What gas do you breathe out as waste?", options: ["Oxygen", "Nitrogen", "Carbon dioxide"], answer: 2, explanation: "You breathe out carbon dioxide — it's a waste product from your cells using oxygen to make energy!" },
    { question: "What is the windpipe called?", options: ["Oesophagus", "Trachea", "Bronchus"], answer: 1, explanation: "The windpipe is called the trachea — it carries air from your throat down to your lungs!" },
    { question: "What are bronchi?", options: ["Tiny air sacs", "The two main tubes that branch into each lung", "Blood vessels in the lungs"], answer: 1, explanation: "The bronchi are two tubes that branch off the trachea — one goes to each lung, then branches further!" },
    { question: "What are the tiny air sacs in the lungs called?", options: ["Bronchi", "Alveoli", "Capillaries"], answer: 1, explanation: "Alveoli are tiny air sacs where oxygen passes into the blood and carbon dioxide passes out — you have about 600 million!" },
    { question: "How many alveoli are in your lungs?", options: ["About 6,000", "About 600,000", "About 600 million"], answer: 2, explanation: "You have about 600 million alveoli — if spread flat, they'd cover an area about the size of a tennis court!" },
    { question: "What muscle helps you breathe?", options: ["The bicep", "The diaphragm", "The heart"], answer: 1, explanation: "The diaphragm is a dome-shaped muscle below your lungs — when it contracts, your lungs expand and air rushes in!" },
    { question: "What causes hiccups?", options: ["Laughing too much", "Involuntary spasms of the diaphragm", "Eating too fast always"], answer: 1, explanation: "Hiccups are caused by involuntary spasms of the diaphragm — the 'hic' sound comes from your vocal cords snapping shut!" },
    { question: "What causes a sneeze?", options: ["Cold weather", "Irritation in the nasal passages", "Deep breathing"], answer: 1, explanation: "A sneeze is a reflex to clear irritants from your nose — air can leave your nose at over 160 km/h!" },
    { question: "How fast can a sneeze travel?", options: ["About 10 km/h", "About 50 km/h", "Over 160 km/h"], answer: 2, explanation: "A sneeze can travel at over 160 km/h and send droplets up to 8 metres — that's why you should cover your nose!" },
    { question: "How fast can a cough travel?", options: ["About 10 km/h", "About 80 km/h", "About 50 km/h"], answer: 1, explanation: "A cough can send air out at about 80 km/h — it's your body's way of clearing your airways!" },
    { question: "What is a yawn?", options: ["A sign of boredom only", "A deep breath that may help cool the brain", "A type of cough"], answer: 1, explanation: "Scientists think yawning may help cool the brain and increase alertness — and it's contagious because of empathy!" },
    { question: "What happens to your ribs when you breathe in?", options: ["They stay still", "They move outward and upward", "They move inward"], answer: 1, explanation: "When you breathe in, your ribs move outward and upward — making your chest bigger so your lungs can expand!" },
    { question: "Can you breathe manually and automatically?", options: ["Only automatically", "Yes, breathing works both ways", "Only manually"], answer: 1, explanation: "Breathing is one of the few body functions that works both automatically and under your voluntary control!" },
    { question: "What is the voice box called?", options: ["Pharynx", "Larynx", "Trachea"], answer: 1, explanation: "The larynx (voice box) contains your vocal cords — air passing over them makes them vibrate to create sound!" },
    { question: "Why does your voice change during a cold?", options: ["Your lungs shrink", "Swollen vocal cords vibrate differently", "Your mouth changes shape"], answer: 1, explanation: "When you have a cold, your vocal cords can become swollen — this changes how they vibrate, making your voice sound different!" },
    { question: "What percentage of the air you breathe is oxygen?", options: ["About 21%", "About 50%", "About 78%"], answer: 0, explanation: "Only about 21% of the air is oxygen — most of it (78%) is nitrogen!" },

    // ===== DIGESTIVE SYSTEM (291-350) =====
    { question: "How long is the digestive system from mouth to end?", options: ["About 2 metres", "About 5 metres", "About 9 metres"], answer: 2, explanation: "Your digestive system is about 9 metres long — it's all coiled up inside your body!" },
    { question: "Where does digestion begin?", options: ["In the stomach", "In the mouth", "In the intestines"], answer: 1, explanation: "Digestion begins in your mouth — your teeth break food down and saliva starts dissolving it!" },
    { question: "How much saliva do you produce daily?", options: ["About a cup", "About 1-2 litres", "About 5 litres"], answer: 1, explanation: "You produce about 1-2 litres of saliva every day — it contains enzymes that start breaking down food!" },
    { question: "What does the oesophagus do?", options: ["Makes stomach acid", "Carries food from throat to stomach", "Absorbs nutrients"], answer: 1, explanation: "The oesophagus is a muscular tube that pushes food from your throat down to your stomach using wave-like contractions!" },
    { question: "What is peristalsis?", options: ["A disease", "Wave-like muscle contractions that move food through the digestive system", "A type of enzyme"], answer: 1, explanation: "Peristalsis is the wave-like muscle contractions that push food through your digestive system — it works even if you're upside down!" },
    { question: "Can you eat upside down?", options: ["No, food needs gravity", "Yes, peristalsis pushes food regardless of position", "Only liquids"], answer: 1, explanation: "You can eat upside down because peristalsis (muscle contractions) pushes food through — astronauts eat in zero gravity!" },
    { question: "What does the stomach do?", options: ["Only stores food", "Churns food and breaks it down with acid", "Absorbs all nutrients"], answer: 1, explanation: "The stomach churns food and breaks it down with powerful hydrochloric acid and digestive enzymes!" },
    { question: "How strong is stomach acid?", options: ["Very weak", "Strong enough to dissolve metal", "As strong as water"], answer: 1, explanation: "Stomach acid (hydrochloric acid) is strong enough to dissolve metal — your stomach lining replaces itself every few days to protect itself!" },
    { question: "How long does food stay in your stomach?", options: ["About 5 minutes", "About 2-5 hours", "About 24 hours"], answer: 1, explanation: "Food usually stays in your stomach for 2-5 hours — liquids pass through faster than solids!" },
    { question: "What is the small intestine's main job?", options: ["Storing waste", "Absorbing nutrients from food", "Making stomach acid"], answer: 1, explanation: "The small intestine absorbs most of the nutrients from digested food into your bloodstream!" },
    { question: "How long is the small intestine?", options: ["About 1 metre", "About 6 metres", "About 20 metres"], answer: 1, explanation: "The small intestine is about 6 metres long — but it's called 'small' because it's narrow, only about 2.5 cm wide!" },
    { question: "What increases the surface area of the small intestine?", options: ["Its length", "Tiny finger-like projections called villi", "Its colour"], answer: 1, explanation: "Villi are tiny finger-like projections lining the small intestine — they massively increase the surface area for absorbing nutrients!" },
    { question: "What does the large intestine do?", options: ["Digests food", "Absorbs water and forms waste", "Produces enzymes"], answer: 1, explanation: "The large intestine absorbs water from leftover food material and forms solid waste (faeces)!" },
    { question: "How long is the large intestine?", options: ["About 0.5 metres", "About 1.5 metres", "About 6 metres"], answer: 1, explanation: "The large intestine is about 1.5 metres long — it's called 'large' because it's wider than the small intestine!" },
    { question: "What does the liver do?", options: ["Only makes bile", "Over 500 vital functions including cleaning blood", "Only stores sugar"], answer: 1, explanation: "The liver performs over 500 functions — including cleaning blood, making bile, storing nutrients, and processing toxins!" },
    { question: "What is the largest internal organ?", options: ["The heart", "The liver", "The stomach"], answer: 1, explanation: "The liver is the largest internal organ — it weighs about 1.5 kg in adults!" },
    { question: "What does bile do?", options: ["Kills bacteria", "Breaks down fats", "Absorbs water"], answer: 1, explanation: "Bile is made by the liver and stored in the gallbladder — it helps break down fats in the small intestine!" },
    { question: "What does the pancreas do?", options: ["Filters blood", "Makes digestive enzymes and insulin", "Pumps blood"], answer: 1, explanation: "The pancreas makes digestive enzymes to break down food and produces insulin to control blood sugar levels!" },
    { question: "How long does it take food to travel through the entire digestive system?", options: ["About 2 hours", "About 24-72 hours", "About 1 week"], answer: 1, explanation: "Food takes about 24-72 hours to travel through your entire digestive system from mouth to end!" },
    { question: "What is the appendix?", options: ["A vital organ", "A small pouch attached to the large intestine", "Part of the stomach"], answer: 1, explanation: "The appendix is a small pouch attached to the large intestine — scientists think it may help store good bacteria!" },

    // ===== THE SENSES (351-400) =====
    { question: "How many senses do humans have?", options: ["5", "At least 9", "Only 3"], answer: 1, explanation: "Beyond the classic 5, we also have senses of balance, temperature, pain, and body position (proprioception)!" },
    { question: "What part of the eye controls how much light enters?", options: ["The retina", "The iris", "The cornea"], answer: 1, explanation: "The iris is the coloured part of your eye — it adjusts the size of the pupil to control how much light enters!" },
    { question: "What is the black part of the eye called?", options: ["The iris", "The pupil", "The cornea"], answer: 1, explanation: "The pupil is the black opening in the centre of the iris — it gets bigger in the dark and smaller in bright light!" },
    { question: "What are the light-detecting cells in the eye called?", options: ["Rods and cones", "Iris and pupil", "Cornea and lens"], answer: 0, explanation: "Rods detect light and dark, while cones detect colour — you have about 120 million rods and 6 million cones!" },
    { question: "Can the human eye see in complete darkness?", options: ["Yes", "No, eyes need some light to see", "Only some people can"], answer: 1, explanation: "Eyes need at least some light to see — in complete darkness, there are no light rays for the eye to detect!" },
    { question: "How many colours can the human eye see?", options: ["About 1,000", "About 100,000", "About 10 million"], answer: 2, explanation: "The human eye can distinguish about 10 million different colours using three types of cone cells!" },
    { question: "What is colour blindness?", options: ["Not being able to see at all", "Difficulty distinguishing certain colours", "Only seeing in black and white"], answer: 1, explanation: "Colour blindness means difficulty telling certain colours apart — most commonly red and green!" },
    { question: "What part of the ear is visible on the outside?", options: ["The eardrum", "The pinna (auricle)", "The cochlea"], answer: 1, explanation: "The pinna is the visible outer ear — it funnels sound waves into the ear canal!" },
    { question: "What is the eardrum?", options: ["A bone in the ear", "A thin membrane that vibrates when sound hits it", "A liquid in the ear"], answer: 1, explanation: "The eardrum (tympanic membrane) is a thin piece of tissue that vibrates when sound waves hit it!" },
    { question: "What gives us our sense of balance?", options: ["Our feet", "The vestibular system in the inner ear", "Our brain only"], answer: 1, explanation: "The vestibular system in your inner ear contains fluid-filled canals that detect head movement and help you balance!" },
    { question: "How many taste areas are there on the tongue?", options: ["4", "5", "The whole tongue tastes everything"], answer: 2, explanation: "Contrary to the old tongue map myth, all areas of the tongue can detect all tastes — sweet, sour, salty, bitter, and umami!" },
    { question: "What is the fifth taste called?", options: ["Spicy", "Umami", "Tangy"], answer: 1, explanation: "Umami is the fifth basic taste — it's a savoury flavour found in foods like cheese, mushrooms, and soy sauce!" },
    { question: "How many taste buds does a human have?", options: ["About 100", "About 2,000-10,000", "About 1 million"], answer: 1, explanation: "You have between 2,000 and 10,000 taste buds — they're mostly on your tongue but also on your palate and throat!" },
    { question: "Why can't you taste food when you have a blocked nose?", options: ["Your tongue stops working", "Much of what we call taste is actually smell", "Food changes when you're ill"], answer: 1, explanation: "About 80% of what we perceive as taste is actually smell — that's why food tastes bland when your nose is blocked!" },
    { question: "How many smells can the human nose detect?", options: ["About 100", "About 10,000", "About 1 trillion"], answer: 2, explanation: "The human nose can detect about 1 trillion different smells — it's far more sensitive than we once thought!" },
    { question: "What are the tiny hairs in the nose that detect smells?", options: ["Cilia", "Olfactory receptors", "Taste buds"], answer: 1, explanation: "Olfactory receptors are special nerve endings in the upper part of your nose that detect smell molecules!" },
    { question: "What part of the skin detects touch?", options: ["Hair follicles only", "Nerve endings and special receptors", "Blood vessels"], answer: 1, explanation: "Your skin has many types of nerve endings and receptors that detect pressure, temperature, vibration, and pain!" },
    { question: "Which body parts are most sensitive to touch?", options: ["Your back", "Your fingertips and lips", "Your knees"], answer: 1, explanation: "Fingertips and lips have the most touch receptors — that's why you explore textures with your fingers!" },
    { question: "What is proprioception?", options: ["The sense of sight", "The sense of knowing where your body parts are without looking", "The sense of taste"], answer: 1, explanation: "Proprioception is your body's ability to sense its own position and movement — try touching your nose with your eyes closed!" },
    { question: "Why do optical illusions trick our eyes?", options: ["Our eyes are broken", "Our brain interprets visual information based on assumptions", "Illusions use magic"], answer: 1, explanation: "Optical illusions exploit the way our brain interprets visual information — our brain makes assumptions that can be wrong!" },

    // ===== SKIN, HAIR & NAILS (401-440) =====
    { question: "What is the largest organ of the body?", options: ["The liver", "The skin", "The brain"], answer: 1, explanation: "The skin is the largest organ — an adult's skin covers about 2 square metres and weighs about 3.6 kg!" },
    { question: "How many layers does the skin have?", options: ["2", "3", "5"], answer: 1, explanation: "The skin has 3 main layers — the epidermis (outer), dermis (middle), and hypodermis (innermost)!" },
    { question: "What gives skin its colour?", options: ["Blood", "A pigment called melanin", "Vitamin D"], answer: 1, explanation: "Melanin is a pigment produced by cells called melanocytes — more melanin means darker skin!" },
    { question: "How often does your skin completely replace itself?", options: ["Every week", "About every 27 days", "Once a year"], answer: 1, explanation: "Your skin completely replaces itself roughly every 27 days — you shed about 600,000 skin particles every hour!" },
    { question: "How much dead skin does a person shed in a lifetime?", options: ["About 5 kg", "About 50 kg", "About 100 kg"], answer: 2, explanation: "You shed about 100 kg of dead skin in your lifetime — much of the dust in your home is actually dead skin!" },
    { question: "What is a fingerprint?", options: ["Dirt on your finger", "A unique pattern of ridges on your fingertip", "A type of skin cell"], answer: 1, explanation: "Fingerprints are unique patterns of ridges — no two people (not even identical twins) have exactly the same fingerprints!" },
    { question: "What is hair mostly made of?", options: ["Living cells", "A protein called keratin", "Calcium"], answer: 1, explanation: "Hair is mostly made of keratin — the same protein found in your nails and the outer layer of your skin!" },
    { question: "How many hairs are on the average head?", options: ["About 10,000", "About 100,000", "About 1 million"], answer: 1, explanation: "The average head has about 100,000 hairs — blondes tend to have more (120,000) and redheads fewer (80,000)!" },
    { question: "How fast does hair grow?", options: ["About 1 mm per day", "About 1 cm per month", "About 1 cm per week"], answer: 1, explanation: "Hair grows about 1 centimetre per month, or about 15 centimetres per year!" },
    { question: "How fast do fingernails grow?", options: ["About 1 mm per week", "About 3.5 mm per month", "About 1 cm per week"], answer: 1, explanation: "Fingernails grow about 3.5 mm per month — that's about twice as fast as toenails!" },
    { question: "What protects your skin from UV rays?", options: ["Sweat", "Melanin", "Oil"], answer: 1, explanation: "Melanin absorbs UV radiation to protect your skin cells — that's why skin tans in the sun!" },
    { question: "Why do you get goosebumps?", options: ["You're scared", "Tiny muscles pull hairs upright", "Your skin shrinks"], answer: 1, explanation: "Goosebumps happen when tiny muscles (arrector pili) contract to pull hairs upright — an ancient reflex to look bigger or stay warm!" },
    { question: "What causes freckles?", options: ["Dirt", "Clusters of melanin triggered by sunlight", "A skin disease"], answer: 1, explanation: "Freckles are caused by clusters of melanin in the skin that become more visible with sun exposure!" },
    { question: "How many sweat glands do you have?", options: ["About 100", "About 100,000", "About 2-4 million"], answer: 2, explanation: "You have between 2 and 4 million sweat glands all over your body — they help you cool down!" },
    { question: "Why do we sweat?", options: ["To get rid of excess water", "To cool the body down", "Because we're nervous only"], answer: 1, explanation: "Sweating is your body's cooling system — as sweat evaporates from your skin, it takes heat with it!" },

    // ===== TEETH & MOUTH (441-460) =====
    { question: "How many baby teeth do children get?", options: ["10", "20", "32"], answer: 1, explanation: "Children get 20 baby (primary) teeth — these start falling out around age 6 to make room for adult teeth!" },
    { question: "How many adult teeth do humans have?", options: ["20", "28", "32"], answer: 2, explanation: "Adults have 32 teeth including wisdom teeth — though many people have their wisdom teeth removed!" },
    { question: "What is the hardest substance in the human body?", options: ["Bone", "Tooth enamel", "Fingernails"], answer: 1, explanation: "Tooth enamel is the hardest substance in your body — it's even harder than bone!" },
    { question: "What are the four types of teeth?", options: ["Big, medium, small, tiny", "Incisors, canines, premolars, molars", "Front, back, side, top"], answer: 1, explanation: "The four types are incisors (cutting), canines (tearing), premolars (crushing), and molars (grinding)!" },
    { question: "What is plaque?", options: ["A type of tooth", "A sticky film of bacteria on teeth", "A filling material"], answer: 1, explanation: "Plaque is a sticky film of bacteria that forms on teeth — if not removed by brushing, it can cause cavities!" },
    { question: "What causes tooth decay?", options: ["Drinking water", "Bacteria producing acid that dissolves enamel", "Brushing too much"], answer: 1, explanation: "Bacteria in plaque feed on sugar and produce acid — this acid dissolves tooth enamel, causing cavities!" },
    { question: "How many times should you brush your teeth daily?", options: ["Once", "Twice", "Five times"], answer: 1, explanation: "You should brush your teeth at least twice a day — morning and before bed — for two minutes each time!" },
    { question: "What is the tongue covered in?", options: ["Tiny bumps called taste buds", "Tiny bumps called papillae that contain taste buds", "Smooth muscle only"], answer: 1, explanation: "The tongue is covered in tiny bumps called papillae — these contain your taste buds!" },
    { question: "How strong is the tongue?", options: ["Very weak", "One of the strongest muscles relative to its size", "The same as any other muscle"], answer: 1, explanation: "The tongue is one of the strongest muscles in the body relative to its size — it's also extremely flexible!" },
    { question: "Is the tongue one muscle or many?", options: ["One big muscle", "Made up of 8 muscles", "Made up of 20 muscles"], answer: 1, explanation: "The tongue is made up of 8 intertwined muscles — that's what makes it so flexible and precise!" },

    // ===== IMMUNE SYSTEM & HEALTH (461-500) =====
    { question: "What is the immune system?", options: ["Your muscles", "Your body's defence system against disease", "Your digestive system"], answer: 1, explanation: "The immune system is your body's defence against germs, viruses, and disease — it includes white blood cells, antibodies, and more!" },
    { question: "What are antibodies?", options: ["Medicines you take", "Proteins your body makes to fight specific germs", "A type of blood cell"], answer: 1, explanation: "Antibodies are special proteins made by your immune system — each one is designed to fight a specific germ!" },
    { question: "What is a vaccine?", options: ["A type of antibiotic", "A weakened or inactive germ that trains your immune system", "A vitamin supplement"], answer: 1, explanation: "A vaccine contains weakened or inactive germs — it trains your immune system to recognise and fight them without making you sick!" },
    { question: "What is a fever?", options: ["A disease", "Your body raising its temperature to fight infection", "A type of rash"], answer: 1, explanation: "A fever is your body's way of fighting infection — the higher temperature helps white blood cells work better and slows down germs!" },
    { question: "What is the difference between bacteria and viruses?", options: ["They're the same", "Bacteria are living cells; viruses need a host to reproduce", "Viruses are larger"], answer: 1, explanation: "Bacteria are living single-celled organisms, while viruses are much smaller and need to invade living cells to reproduce!" },
    { question: "What do antibiotics treat?", options: ["Viruses", "Bacterial infections", "Both bacteria and viruses"], answer: 1, explanation: "Antibiotics only work against bacteria — they don't work against viruses like the common cold or flu!" },
    { question: "What organ filters your blood?", options: ["The heart", "The kidneys", "The lungs"], answer: 1, explanation: "Your kidneys filter about 180 litres of blood every day, removing waste and excess water to make urine!" },
    { question: "How much water should you drink per day?", options: ["About 1 glass", "About 6-8 glasses", "About 20 glasses"], answer: 1, explanation: "Children should drink about 6-8 glasses of water a day — more when exercising or in hot weather!" },
    { question: "What percentage of your body is water?", options: ["About 30%", "About 60%", "About 90%"], answer: 1, explanation: "About 60% of the adult body is water — it's involved in almost every body function!" },
    { question: "How much sleep do children need?", options: ["About 5-6 hours", "About 9-12 hours", "About 15 hours"], answer: 1, explanation: "Children aged 6-12 need about 9-12 hours of sleep per night for healthy growth and brain development!" },
    { question: "What happens to your body during sleep?", options: ["Nothing, it just rests", "Cells repair, memories form, and hormones are released", "Only dreams happen"], answer: 1, explanation: "During sleep, your body repairs cells, your brain forms memories, and growth hormones are released — sleep is vital!" },
    { question: "What is the body's core temperature?", options: ["About 30°C", "About 37°C", "About 42°C"], answer: 1, explanation: "Your normal body temperature is about 37°C (98.6°F) — your body works hard to maintain this temperature!" },
    { question: "What vitamin does your skin make from sunlight?", options: ["Vitamin A", "Vitamin C", "Vitamin D"], answer: 2, explanation: "Your skin makes vitamin D when exposed to sunlight — vitamin D is important for strong bones and immune function!" },
    { question: "What food group builds and repairs muscles?", options: ["Carbohydrates", "Proteins", "Fats"], answer: 1, explanation: "Proteins are essential for building and repairing muscles, skin, and other tissues — found in meat, fish, eggs, and beans!" },
    { question: "What food group gives you quick energy?", options: ["Carbohydrates", "Proteins", "Vitamins"], answer: 0, explanation: "Carbohydrates are your body's main source of quick energy — found in bread, pasta, rice, and fruits!" },
    { question: "Are all fats bad for you?", options: ["Yes, all fats are harmful", "No, some fats are essential for health", "Only animal fats are bad"], answer: 1, explanation: "Healthy fats (from fish, nuts, avocados) are essential — they protect organs, help absorb vitamins, and keep you warm!" },
    { question: "Why is exercise important?", options: ["Only to lose weight", "It strengthens muscles, bones, heart, and improves mood", "It's not that important"], answer: 1, explanation: "Exercise strengthens your muscles, bones, and heart, improves mood, helps you sleep better, and keeps you healthy!" },
    { question: "What happens when you exercise?", options: ["Your heart slows down", "Your heart beats faster to pump more oxygen to muscles", "Your brain stops working"], answer: 1, explanation: "During exercise, your heart beats faster and you breathe harder to deliver more oxygen to your working muscles!" },
    { question: "What are the lymph nodes?", options: ["A type of bone", "Small bean-shaped organs that filter germs from lymph fluid", "Blood vessels"], answer: 1, explanation: "Lymph nodes are part of your immune system — they filter germs and contain white blood cells to fight infection!" },
    { question: "Why do lymph nodes swell when you're ill?", options: ["They're filling with water", "They're producing extra white blood cells to fight infection", "They're broken"], answer: 1, explanation: "Swollen lymph nodes mean your immune system is working hard — they're making extra white blood cells to fight the germs!" }
];
